1	interface Item {
2	  type: string;
3	}
4	
5	interface QuoteStep {
6	  op: "quote";
7	  items: Item[];
8	}
9	
10	interface Scenario {
11	  customer: { yearsWithMHPCO: number };
12	  steps: QuoteStep[];
13	}
14	
15	const BASE_PREMIUM: Record<string, number> = {
16	  sword: 100,
17	  amulet: 60,
18	};
19	
20	const FIRST_INSURANCE_SURCHARGE = 1.1;
21	const PROCESSING_FEE = 5;
22	
23	// Round up to a whole number in MHPCO's favour, guarding against
24	// floating-point noise (e.g. 197.5000000001) before the ceiling.
25	const roundUpToWhole = (value: number): number => Math.ceil(Math.round(value * 1e6) / 1e6);
26	
27	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
28	  const results = scenario.steps.map((step) => {
29	    const base = step.items.reduce((sum, item) => sum + (BASE_PREMIUM[item.type] ?? 0), 0);
30	    const premium = base * FIRST_INSURANCE_SURCHARGE + PROCESSING_FEE;
31	    return { premium: roundUpToWhole(premium) };
32	  });
33	  return { results };
34	};
